import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.pdf.co/api-reference/introduction";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from PDF.co API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:pdfco",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const pdfcoFirewall = {",
    '  name: "pdfco",',
    '  description: "PDF.co API",',
    "  placeholders: {",
    `    PDFCO_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.pdf.co",',
    "      auth: {",
    "        headers: {",
    '          "x-api-key": "${{ secrets.PDFCO_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating PDF.co firewall config...");
  const ts = generateTypeScript();
  writeOutput("pdfco", ts, import.meta.dirname);
}
